def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            threshold = j * 0.1
            if ratio < threshold:
                score += (11 - j) * np.log1p(capacity) * np.sqrt(item + j)
            else:
                penalty = j * np.sqrt(item) * (np.log1p(j) + 1)
                score -= penalty
            if j % 3 == 0:
                if capacity < item * (1 + j * 0.1):
                    score *= 1.2
                elif capacity > item * (3 + j * 0.1):
                    score /= 1.3
        if capacity % 2 == 0:
            for k in range(1, 4):
                if capacity - k * item > 0:
                    score += np.exp(-k) * np.log1p(capacity - k * item)
                else:
                    score -= np.exp(k)
        if score < 0:
            score = abs(score) / (1 + ratio)
        else:
            score *= (1 + ratio)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority + 20
    return priorities
